class MyCalendarThree:
    def __init__(self):
        self.prev_events = {}

    def book(self, startTime: int, endTime: int) -> int:
        if startTime in self.prev_events:
            return self.prev_events[startTime]
        self.prev_events[startTime] = len(self.prev_events)
        for event in self.prev_events.values():
            if startTime >= event:
                return len(self.prev_events) - 1
        return len(self.prev_events)
